+    fn resolve_binding_id(&self, id: &BindingId) -> BindingId {
+        let mut current = id.clone();
+        let mut visited = BTreeSet::new();
+
+        while visited.insert(current.clone()) {
+            let Some(next) = self
+                .aliases
+                .iter()
+                .find(|entry| entry.alias == current)
+                .map(|entry| entry.source.clone())
+            else {
+                break;
+            };
+            current = next;
+        }
+
+        current
+    }
